div.t-attf-class:
rpt-kpi-box #{
                                        'positive' if profitability['profit_percentage'] >= 10
                                        else 'negative' if profitability['profit_percentage'] < 0
                                        else 'warning'
                                    }

th.style:
padding:7px 10px; font-size:7.5pt; font-weight:700;
                                               color:#1a237e; border-bottom:2px solid #c5cae9;
                                               text-transform:uppercase; letter-spacing:.06em;

padding:7px 10px; text-align:right; font-size:7.5pt;
                                               font-weight:700; color:#1a237e;
                                               border-bottom:2px solid #c5cae9;
                                               text-transform:uppercase; letter-spacing:.06em;

padding:7px 10px; text-align:right; font-size:7.5pt;
                                               font-weight:700; color:#1a237e;
                                               border-bottom:2px solid #c5cae9;
                                               text-transform:uppercase; letter-spacing:.06em;

padding:7px 10px; text-align:right; font-size:7.5pt;
                                               font-weight:700; color:#1a237e;
                                               border-bottom:2px solid #c5cae9;
                                               text-transform:uppercase; letter-spacing:.06em;

td.t-attf-style:
color: #{'#2e7d32' if profitability['margin_billed'] >= 0 else '#b71c1c'};
font-family: 'DejaVu Sans Mono', monospace;
text-align: right;

color: #{'#2e7d32' if profitability['margin_to_bill'] >= 0 else '#b71c1c'};
font-family: 'DejaVu Sans Mono', monospace;
text-align: right;

color: #{'#2e7d32' if profitability['margin_total'] >= 0 else '#b71c1c'};
font-family: 'DejaVu Sans Mono', monospace;
text-align: right;

span.t-attf-class:
rpt-badge #{
                                                'done'     if inv['state'] == 'posted' and inv['payment_state'] == 'paid'
                                                else 'pending'  if inv['state'] == 'posted'
                                                else 'canceled'
                                            }
